+    { label: "Delete", icon: <Trash2 size={20} />, value: "delete" as const },
+  ];
+
+  const renderContent = () => {
+    switch (action) {
+      case "create":
+        return <CreateUserForm />;
+      //   case 'read':
+      //     return <ReadUserForm />;
+      //   case 'update':
+      //     return <UpdateUserForm />;
+      //   case 'delete':
+      //     return <DeleteUserForm />;
+      default:
+        return null;
+    }
+  };
+
+  return (
+    <div className="space-y-6">
+      {!action ? (
+        <div className="bg-gray-800 border-2 border-purple-500 rounded-lg p-8 shadow-2xl shadow-purple-500/50">
+          <h3 className="text-3xl font-bold text-purple-400 mb-6">Users</h3>
+          <div className="grid grid-cols-2 gap-4">
+            {crudActions.map((item) => (
+              <button
+                key={item.value}
+                onClick={() => setAction(item.value)}
+                className="flex items-center gap-3 px-6 py-4 bg-purple-600 hover:bg-purple-500 text-white font-semibold rounded border-2 border-purple-400 transition-all duration-200 hover:shadow-lg hover:shadow-purple-400/50"
+              >
+                {item.icon}
+                {item.label}
+              </button>
+            ))}
+          </div>
+        </div>
+      ) : (
+        <div className="bg-gray-800 border-2 border-purple-500 rounded-lg p-8 shadow-2xl shadow-purple-500/50">
+          <button
+            onClick={() => setAction(null)}
+            className="mb-4 px-4 py-2 bg-gray-700 hover:bg-gray-600 text-purple-300 font-semibold rounded border-2 border-gray-600 transition-all"
+          >
+            ← Back
+          </button>
+          {renderContent()}
+        </div>
+      )}
+      {/* Error Message */}
+      {error && (
+        <div className="flex items-center gap-3 px-4 py-3 bg-red-900 border-2 border-red-500 text-red-200 rounded">
+          <AlertCircle size={20} />
+          <span className="font-semibold">{error}</span>
+        </div>
+      )}
+
+      {/* Success Message */}
+      {success && data && Array.isArray(data.Users) ? (
+        <>
+          {data.Users.map((item) => {
+            return (
+              <div className="flex gap-3 px-6 py-4 bg-purple-600 hover:bg-purple-500 text-white rounded border-2 border-purple-400 transition-all duration-200 hover:shadow-lg hover:shadow-purple-400/50">
